import { useState, useRef, useEffect } from 'react';

/**
 * InfoTooltip — hover/click "i" circle that shows a definition popup.
 * Glassmorphism design with category badges and smooth animations.
 *
 * Usage: <InfoTooltip term="Portfolio Heat" />
 *    or: <InfoTooltip text="Custom explanation here" />
 */

const DEFINITIONS = {
  // ── Equity & P&L ──
  'Total Equity': 'The combined net liquidation value across all accounts and bots. This is the total worth of your portfolio including cash, open positions, and unrealized gains/losses.',
  'Equity': 'Net liquidation value — total portfolio worth including cash, positions, and unrealized P&L for this account or bot.',
  'Net Liquidation': 'Your total account value if all positions were closed at current market prices. Includes cash balance plus the market value of all holdings.',
  'Day P&L': 'Profit or loss for the current trading day. Calculated as the change in portfolio value since market open, including both realized trades and unrealized position changes.',
  'Week P&L': 'Cumulative profit or loss for the current trading week (Monday to now).',
  'Month P&L': 'Cumulative profit or loss for the current calendar month.',
  'Unrealized P&L': 'Paper profit or loss on positions that are still open. This is the difference between current market value and your average cost basis.',
  'Realized P&L': 'Profit or loss from positions that have been closed. This reflects actual gains or losses locked in through completed trades.',
  'Total P&L': 'The sum of all realized and unrealized profit and loss across the entire portfolio or strategy.',
  'Net P&L': 'Total profit or loss after subtracting commissions, slippage, and other trading costs from gross P&L.',
  'Net Return': 'Percentage return on invested capital after all costs (commissions, slippage, fees).',
  'Gross Profit': 'Total profits from all winning trades before subtracting costs.',
  'Gross Loss': 'Total losses from all losing trades before adding costs.',

  // ── Risk & Exposure ──
  'Portfolio Heat': 'A risk gauge (0-100%) measuring how much of your portfolio is at risk. Combines position concentration, correlation, and proximity to stop losses. Above 80% is considered high risk.',
  'Exposure': 'The total dollar amount of your portfolio currently deployed in open positions. Gross exposure counts both long and short positions.',
  'Total Exposure': 'Gross dollar exposure across all accounts — the sum of absolute position values (longs + shorts). Higher exposure means more capital at risk.',
  'Total Exposure (Gross)': 'Sum of absolute values of all position notional amounts across all bots. Includes both long and short exposure without netting.',
  'Risk Exposure': 'Percentage of portfolio value currently at risk from open positions relative to total equity.',
  'Correlation Risk': 'How correlated your open positions are with each other. High correlation means positions tend to move together, increasing portfolio risk during market swings.',
  'Max Drawdown': 'The largest peak-to-trough decline in portfolio value during the measured period. A drawdown of 15% means the portfolio fell 15% from its highest point before recovering.',

  // ── Buying Power & Capital ──
  'Buying Power': 'The total cash and margin available for new trades. For margin accounts, this includes leverage. For cash accounts, this equals your settled cash balance.',
  'Settled Cash': 'Cash available for immediate use. Stock sales settle T+1 (next business day). Until settlement, proceeds cannot be withdrawn but can be used for new trades.',
  'Available Funds': 'The amount of capital available for new trades after accounting for maintenance margin requirements on existing positions.',
  'Excess Liquidity': 'The surplus above your maintenance margin requirement. If this reaches zero, you may receive a margin call requiring you to close positions or deposit funds.',
  'Maint Margin': 'The minimum equity you must maintain in your margin account. If your equity falls below this level, your broker may liquidate positions to meet the requirement.',
  'Total Capital': 'Aggregate net liquidation value across all accounts and bots managed by the platform.',
  'Capital Util': 'Capital utilization — the percentage of your total equity that is deployed in active positions vs. sitting as cash.',

  // ── Performance Ratios ──
  'Sharpe Ratio': 'Risk-adjusted return metric. Measures excess return per unit of volatility. Above 1.0 is good, above 2.0 is excellent. Higher is better — it means more return for less risk.',
  'Calmar Ratio': 'Annual return divided by maximum drawdown. Measures return relative to worst-case loss. Above 1.0 means annual gains exceed the worst drawdown.',
  'Profit Factor': 'Gross profit divided by gross loss. A factor of 2.0 means you made $2 for every $1 lost. Below 1.0 means the strategy is unprofitable.',
  'Win Rate': 'Percentage of trades that were profitable. A 60% win rate means 6 out of every 10 trades made money. Win rate alone doesn\'t indicate profitability — risk:reward ratio matters too.',
  'Win Streak': 'The longest consecutive run of winning trades during the measured period.',
  'Lose Streak': 'The longest consecutive run of losing trades during the measured period.',
  'CAGR': 'Compound Annual Growth Rate — the annualized return of the strategy, smoothed over the backtest period. Accounts for compounding.',

  // ── Trading Costs ──
  'Commissions': 'Total broker fees charged for executing trades. Includes per-share/per-contract commissions and exchange fees.',
  'Slippage': 'The difference between expected execution price and actual fill price. Occurs due to market movement between order submission and execution, especially in fast-moving or illiquid markets.',

  // ── Bot & System ──
  'Positions': 'The number of currently open positions (stocks, options, or crypto) held by this bot or account.',
  'Open Positions': 'Total number of active holdings across all accounts — securities or crypto assets you currently own or are short.',
  'Trades (Filled)': 'The number of trade orders that have been fully executed (filled) by the broker. Does not include pending or cancelled orders.',
  'Strategies': 'The number of trading strategies currently active and generating signals for this bot.',
  'Active Signals': 'The number of strategy signals currently flagged for potential entry. Not all signals result in trades — they must pass risk and approval filters first.',
  'Avg Signal Strength': 'Average confidence score across all active signals (0-100%). Higher strength means more technical indicators agree on the setup.',
  'Avg Risk:Reward': 'Average ratio of potential reward to potential risk across active signals. A 3:1 ratio means expected gain is 3x the expected loss.',
  'Live Strategies': 'Number of strategies promoted to LIVE status, actively scanning for trade setups in real-time.',
  'Top Signal': 'The strategy signal with the highest confidence/strength score right now.',
  'Best R:R': 'The signal with the best (highest) risk-to-reward ratio among all active signals.',
  'Bots Online': 'Number of trading bots currently sending heartbeats and reporting as active.',
  'Avg Heartbeat': 'Average time since last heartbeat across all bots. Lower is better — indicates bots are responsive.',
  'System Load': 'Current CPU utilization of the server running the trading platform.',
  'Uptime': 'How long the trading platform API has been running without restart.',

  // ── V2 Dashboard ──
  'API': 'The FastAPI backend server status. Green means the control plane is responding to requests.',
  'Approvals': 'Pending strategy promotion approvals waiting for review. Strategies must be explicitly approved before they can trade live.',
  'Execution': 'Order execution pipeline status. Shows whether the system can successfully route and fill orders through connected brokers.',
  'Backtest': 'Background backtesting engine status. Shows if backtests are running and their progress.',

  // ── Account-level ──
  'Total Buying Power': 'Combined buying power across all connected accounts, including any margin available.',
  'VaR (1d, 95%)': 'Value at Risk — the maximum expected loss over one trading day with 95% confidence. A VaR of $500 means there is only a 5% chance of losing more than $500 in a single day.',
};

/* ── Category badges for each term ─────────────────────────────────────── */
const CATEGORIES = {
  'Total Equity': 'EQUITY',  'Equity': 'EQUITY',  'Net Liquidation': 'EQUITY',
  'Day P&L': 'P&L',  'Week P&L': 'P&L',  'Month P&L': 'P&L',
  'Unrealized P&L': 'P&L',  'Realized P&L': 'P&L',  'Total P&L': 'P&L',
  'Net P&L': 'P&L',  'Net Return': 'P&L',  'Gross Profit': 'P&L',  'Gross Loss': 'P&L',
  'Portfolio Heat': 'RISK',  'Exposure': 'RISK',  'Total Exposure': 'RISK',
  'Total Exposure (Gross)': 'RISK',  'Risk Exposure': 'RISK',
  'Correlation Risk': 'RISK',  'Max Drawdown': 'RISK',
  'Buying Power': 'CAPITAL',  'Settled Cash': 'CAPITAL',  'Available Funds': 'CAPITAL',
  'Excess Liquidity': 'CAPITAL',  'Maint Margin': 'CAPITAL',
  'Total Capital': 'CAPITAL',  'Capital Util': 'CAPITAL',  'Total Buying Power': 'CAPITAL',
  'Sharpe Ratio': 'PERFORMANCE',  'Calmar Ratio': 'PERFORMANCE',
  'Profit Factor': 'PERFORMANCE',  'Win Rate': 'PERFORMANCE',
  'Win Streak': 'PERFORMANCE',  'Lose Streak': 'PERFORMANCE',  'CAGR': 'PERFORMANCE',
  'Commissions': 'COSTS',  'Slippage': 'COSTS',
  'Positions': 'SYSTEM',  'Open Positions': 'SYSTEM',  'Trades (Filled)': 'SYSTEM',
  'Strategies': 'SYSTEM',  'Active Signals': 'SYSTEM',  'Avg Signal Strength': 'SYSTEM',
  'Avg Risk:Reward': 'SYSTEM',  'Live Strategies': 'SYSTEM',
  'Top Signal': 'SYSTEM',  'Best R:R': 'SYSTEM',
  'Bots Online': 'SYSTEM',  'Avg Heartbeat': 'SYSTEM',
  'System Load': 'INFRA',  'Uptime': 'INFRA',
  'API': 'INFRA',  'Approvals': 'SYSTEM',  'Execution': 'SYSTEM',  'Backtest': 'SYSTEM',
  'VaR (1d, 95%)': 'RISK',
};

const CATEGORY_COLORS = {
  'EQUITY':      { bg: 'rgba(96, 165, 250, 0.12)', text: '#60A5FA', border: 'rgba(96, 165, 250, 0.25)' },
  'P&L':         { bg: 'rgba(34, 197, 94, 0.12)',  text: '#22C55E', border: 'rgba(34, 197, 94, 0.25)' },
  'RISK':        { bg: 'rgba(239, 68, 68, 0.12)',  text: '#EF4444', border: 'rgba(239, 68, 68, 0.25)' },
  'CAPITAL':     { bg: 'rgba(245, 158, 11, 0.12)', text: '#F59E0B', border: 'rgba(245, 158, 11, 0.25)' },
  'PERFORMANCE': { bg: 'rgba(167, 139, 250, 0.12)', text: '#A78BFA', border: 'rgba(167, 139, 250, 0.25)' },
  'COSTS':       { bg: 'rgba(251, 113, 133, 0.12)', text: '#FB7185', border: 'rgba(251, 113, 133, 0.25)' },
  'SYSTEM':      { bg: 'rgba(54, 189, 240, 0.12)', text: '#36BDF0', border: 'rgba(54, 189, 240, 0.25)' },
  'INFRA':       { bg: 'rgba(144, 163, 175, 0.12)', text: '#90A3AF', border: 'rgba(144, 163, 175, 0.25)' },
};

export function getDefinition(term) {
  return DEFINITIONS[term] || null;
}

export default function InfoTooltip({ term, text, size = 14 }) {
  const [open, setOpen] = useState(false);
  const ref = useRef(null);
  const tipRef = useRef(null);
  const definition = text || getDefinition(term) || `${term}: No definition available.`;
  const category = term ? CATEGORIES[term] : null;
  const catStyle = category ? CATEGORY_COLORS[category] : null;

  // Close on click outside
  useEffect(() => {
    if (!open) return;
    const handler = (e) => {
      if (ref.current && !ref.current.contains(e.target)) setOpen(false);
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, [open]);

  // Position tooltip within viewport
  useEffect(() => {
    if (!open || !tipRef.current) return;
    const rect = tipRef.current.getBoundingClientRect();
    if (rect.right > window.innerWidth - 12) {
      tipRef.current.style.left = 'auto';
      tipRef.current.style.right = '0';
    }
    if (rect.bottom > window.innerHeight - 12) {
      tipRef.current.style.top = 'auto';
      tipRef.current.style.bottom = `${size + 8}px`;
    }
  }, [open, size]);

  return (
    <span ref={ref} style={{ position: 'relative', display: 'inline-flex', alignItems: 'center', marginLeft: 4 }}>
      {/* ── Trigger icon ── */}
      <span
        onClick={(e) => { e.stopPropagation(); setOpen(o => !o); }}
        onMouseEnter={() => setOpen(true)}
        onMouseLeave={() => setOpen(false)}
        style={{
          display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
          width: size, height: size, borderRadius: '50%',
          border: '1.5px solid rgba(139, 148, 158, 0.25)',
          color: 'rgba(139, 148, 158, 0.6)',
          fontSize: size - 5, fontWeight: 700,
          fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
          fontStyle: 'normal',
          cursor: 'help', userSelect: 'none',
          transition: 'all 0.25s cubic-bezier(0.2, 0.8, 0.2, 1)',
          lineHeight: 1,
        }}
        onMouseOver={(e) => {
          e.currentTarget.style.borderColor = 'rgba(54, 189, 240, 0.5)';
          e.currentTarget.style.color = '#36BDF0';
          e.currentTarget.style.background = 'rgba(54, 189, 240, 0.08)';
          e.currentTarget.style.boxShadow = '0 0 0 3px rgba(54, 189, 240, 0.06)';
          e.currentTarget.style.transform = 'scale(1.1)';
        }}
        onMouseOut={(e) => {
          e.currentTarget.style.borderColor = 'rgba(139, 148, 158, 0.25)';
          e.currentTarget.style.color = 'rgba(139, 148, 158, 0.6)';
          e.currentTarget.style.background = 'transparent';
          e.currentTarget.style.boxShadow = 'none';
          e.currentTarget.style.transform = 'scale(1)';
        }}
      >
        i
      </span>

      {/* ── Tooltip popup — glassmorphism ── */}
      {open && (
        <span
          ref={tipRef}
          style={{
            position: 'absolute', top: size + 8, left: -8, zIndex: 9999,
            width: 300, padding: '0',
            background: 'rgba(15, 22, 32, 0.88)',
            backdropFilter: 'blur(16px) saturate(1.4)',
            WebkitBackdropFilter: 'blur(16px) saturate(1.4)',
            border: '1px solid rgba(54, 189, 240, 0.1)',
            borderRadius: 14,
            boxShadow: '0 8px 32px rgba(0,0,0,0.5), 0 0 0 1px rgba(255,255,255,0.03), 0 0 40px rgba(54,189,240,0.03)',
            fontSize: 13, lineHeight: 1.55, fontWeight: 400,
            fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
            fontStyle: 'normal',
            color: '#C9D1D9',
            pointerEvents: 'none',
            overflow: 'hidden',
            animation: 'tooltipIn 180ms cubic-bezier(0.2, 0.8, 0.2, 1) forwards',
          }}
        >
          {/* Top accent gradient line */}
          <span style={{
            display: 'block',
            height: 2,
            background: catStyle
              ? `linear-gradient(90deg, ${catStyle.text}, transparent)`
              : 'linear-gradient(90deg, #36BDF0, transparent)',
            borderRadius: '2px 2px 0 0',
          }} />

          <span style={{ display: 'block', padding: '12px 14px 14px' }}>
            {/* Category badge + term header */}
            {(category || term) && (
              <span style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 8 }}>
                {category && catStyle && (
                  <span style={{
                    display: 'inline-block',
                    padding: '2px 7px',
                    borderRadius: 6,
                    background: catStyle.bg,
                    border: `1px solid ${catStyle.border}`,
                    color: catStyle.text,
                    fontSize: 10,
                    fontWeight: 700,
                    letterSpacing: 0.8,
                    lineHeight: '14px',
                  }}>
                    {category}
                  </span>
                )}
                {term && (
                  <span style={{
                    fontSize: 11,
                    fontWeight: 700,
                    color: '#E5E7DB',
                    letterSpacing: 0.2,
                  }}>
                    {term}
                  </span>
                )}
              </span>
            )}
            {/* Definition text */}
            <span style={{ display: 'block', color: 'rgba(201, 209, 217, 0.85)' }}>
              {definition}
            </span>
          </span>
        </span>
      )}

      {/* Inline animation keyframes */}
      {open && (
        <style>{`
          @keyframes tooltipIn {
            from { opacity: 0; transform: translateY(4px) scale(0.97); }
            to { opacity: 1; transform: translateY(0) scale(1); }
          }
        `}</style>
      )}
    </span>
  );
}
